import { motion } from "framer-motion";

import { DB_IMANES_ARRASTRE } from "../../consts/dbs";

import { toPriceFormat } from "../../libs/functions";

import ButtonAddCart from "../../components/ButtonAddCart";

import { Button } from "@nextui-org/react";
import { FaRegEye } from "react-icons/fa";

import { SVGDragMagnet } from "../../assets/imanes/svgs";

function DragMagnets({ handleAdd, setComparative, cartCat = {} }) {
  const cols = ["B", "C", "peso", "fuerza"];
  const cols_measure = {
    B: "mm",
    C: "mm",
    peso: "g",
    fuerza: "kg",
  };

  return (
    <>
      <motion.div
        className="flex items-center justify-center h-[250px]"
        variants={{
          hidden: { opacity: 0 },
          visible: { opacity: 1 },
        }}
        initial="hidden"
        whileInView="visible"
      >
        <SVGDragMagnet className="h-full w-full max-h-[250px]" />
      </motion.div>

      <div
        data-slot="table-container"
        className="pb-4 sm:px-4 w-full overflow-x-auto scrollbar scrollbar-thumb-rounded-full scrollbar-track-rounded-full scrollbar-thumb-custom1 scrollbar-track-custom2-10 scrollbar-w-3 scrollbar-h-3 hover:scrollbar-thumb-custom1-6"
      >
        <table
          aria-label="Tabla de precios: imanes de arrastre"
          className="w-full min-w-[600px] max-w-[800px] text-xl xs:text-2xl font-semibold md:place-self-center sm:w-fit"
        >
          <thead className="border-b-3">
            <tr>
              <td className="p-2 border-e-3">
                <p>A</p>
                (mm)
              </td>

              {cols.map((col) => (
                <td key={col} className="p-2">
                  <div className="flex flex-col gap-1">
                    <span className="capitalize">{col}</span>(
                    {cols_measure?.[col]})
                  </div>
                </td>
              ))}

              <td className="p-2">Precio</td>
            </tr>
          </thead>

          <tbody>
            {Object.entries(DB_IMANES_ARRASTRE)?.map(([size, info]) => {
              const noStock = info?.noStock || false;
              const discount = info?.discountObj || false;
              const inCart = cartCat && size in cartCat;

              if (discount) {
                if (discount?.fix) {
                  discount.price = info?.price - discount.fix;
                  discount.percentage = discount.fix / info?.price;
                } else if (discount?.percentage) {
                  discount.price = info?.price * (1 - discount.percentage);
                }
              }

              return (
                <motion.tr
                  key={size}
                  className={`even:text-custom1 hover:bg-custom2 odd:hover:text-white border-y${
                    noStock ? " bg-divider" : ""
                  }`}
                  variants={{
                    hidden: { opacity: 0 },
                    visible: { opacity: 1 },
                  }}
                >
                  <td className="p-2 text-start border-e-3 whitespace-nowrap">
                    <Button
                      color="secondary"
                      isIconOnly
                      className="shadow-md me-2"
                      onPress={() =>
                        setComparative({
                          form: "de_arrastre",
                          size: `${size}x${info?.B}`,
                        })
                      }
                    >
                      <FaRegEye size={18} />
                    </Button>
                    {size}
                  </td>

                  {cols.map((col) => (
                    <td key={`${size}_${col}`} className="p-2">
                      {info?.[col]}
                    </td>
                  ))}

                  <td className="p-2">
                    <div className="flex gap-2 justify-end items-center">
                      <div>
                        {discount && (
                          <>
                            <div className="text-lg text-danger font-bold">
                              -
                              {Intl.NumberFormat("es-AR", {
                                style: "percent",
                                minimumFractionDigits: 0,
                                maximumFractionDigits: 0,
                              }).format(discount.percentage)}
                            </div>
                            <div>{toPriceFormat(discount.price)}</div>
                          </>
                        )}

                        <div
                          className={`${
                            discount && "line-through text-neutral-500 text-lg"
                          }`}
                        >
                          {toPriceFormat(info?.price)}
                        </div>
                      </div>

                      <ButtonAddCart
                        catId={"de_arrastre"}
                        cartData={{
                          id: size,
                          qtt: 1,
                        }}
                        inCart={inCart && cartCat[size]?.qtt === 1}
                        handleAdd={handleAdd}
                      />
                    </div>
                  </td>
                </motion.tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </>
  );
}

export default DragMagnets;
