import { Button } from "@nextui-org/react";
import { FaCartPlus } from "react-icons/fa";

export default function ButtonAddCart({
  catId = "",
  cartData = {},
  inCart = false,
  handleAdd = () => {},
}) {
  const color = inCart ? "success" : "secondary";
  if (inCart) {
    cartData.qtt = 0;
  } else {
    if (!cartData?.qtt) cartData.qtt = 1;
  }

  return (
    <Button
      color={color}
      isIconOnly
      className="shadow-md"
      onPress={() => {
        handleAdd(catId, cartData);
      }}
    >
      <FaCartPlus size={18} />
    </Button>
  );
}
