import { useEffect, useRef } from "react";
import { motion, useInView } from "framer-motion";

import { toPriceFormat } from "../../libs/functions";
import { DB_IMANES_PRICES } from "../../consts/dbs";

import { Button } from "@nextui-org/react";

import ButtonAddCart from "../../components/ButtonAddCart";

import { FaRegEye } from "react-icons/fa";

function TablePrices({
  cat,
  setComparative,
  handleAdd,
  formsData,
  data,
  showMore,
  cartCat = {},
}) {
  const discounts = false;
  const ref = useRef(null);
  const isInView = useInView(ref);

  useEffect(() => {
    if (isInView) showMore(cat);
  }, [isInView]);

  return (
    <div
      data-slot="table-container"
      className="pb-4 w-full overflow-x-auto scrollbar scrollbar-thumb-rounded-full scrollbar-track-rounded-full scrollbar-thumb-custom1 scrollbar-track-custom2-10 scrollbar-w-3 scrollbar-h-3 hover:scrollbar-thumb-custom1-6"
    >
      <table
        aria-label={`Tabla de precios: ${formsData?.[cat]?.label}`}
        className="w-full sm:min-w-[750px] max-w-[900px] text-xl xs:text-2xl font-semibold lg:place-self-center table-dinamic max-sm:border-separate border-spacing-y-3"
      >
        <thead className="border-b-3">
          <tr>
            <td className="p-2 border-e-3">
              <p>Medida</p>
              {formsData?.[cat]?.medidas}(mm)
            </td>

            <td colSpan={4} className="p-2">
              <p>
                Precio(xU)
                <span className="font-size-secondary">Unidades minimas</span>
              </p>
            </td>
          </tr>
        </thead>

        <tbody>
          {data?.rows?.map(([size, info]) => {
            const noStock = info?.noStock || false;
            const inCart = cartCat && size in cartCat;
            return (
              <motion.tr
                key={size}
                className="even:text-custom2-10 dark:even:text-custom1 group hover:text-white"
                variants={{
                  hidden: { opacity: 0 },
                  visible: { opacity: 1 },
                }}
              >
                <td
                  className={`p-2 text-start whitespace-nowrap sm:border-e-3 max-sm:border-3 max-sm:rounded-t-lg group-hover:bg-custom2${
                    inCart ? " bg-success/30" : noStock ? " bg-divider" : ""
                  }`}
                  data-label="medida"
                >
                  <div className="flex gap-2 justify-end items-center w-full sm:flex-row-reverse">
                    <span>{size.replace("_", " ")} </span>
                    <Button
                      color="secondary"
                      isIconOnly
                      className="shadow-md"
                      onPress={() => setComparative({ form: cat, size: size })}
                    >
                      <FaRegEye size={18} />
                    </Button>
                  </div>
                </td>

                {[1, 2, 3, 4].map((key, i) => {
                  const price = DB_IMANES_PRICES?.[cat]?.[size]?.prices?.[i];
                  const umin = DB_IMANES_PRICES?.[cat]?.[size]?.qtts?.[i];
                  const discount_ = discounts
                    ? discounts?.[info?.catPrices] || 0
                    : 0;

                  return (
                    <td
                      key={`precio_${key}`}
                      className={`p-2 hover:!text-custom1-5 max-sm:last:border-b-3 max-sm:border-x-3 last:rounded-b-lg group-hover:bg-custom2${
                        noStock ? " bg-divider" : ""
                      }`}
                    >
                      <div className="flex gap-2 justify-end items-center w-full">
                        {i === 0 && discount_ ? (
                          <div className="flex items-center justify-center gap-1">
                            <div className="flex gap-1">
                              <span className="line-through text-neutral-300">
                                {toPriceFormat(price)}
                              </span>

                              {toPriceFormat(price * (1 - discount_))}
                            </div>

                            <div className="text-xs">
                              <span className="text-yellow-400 font-semibold">
                                -
                                {Intl.NumberFormat("es-AR", {
                                  style: "percent",
                                  minimumFractionDigits: 0,
                                  maximumFractionDigits: 0,
                                }).format(discount_)}
                              </span>

                              <span className="font-size-secondary">
                                {umin}u
                              </span>
                            </div>
                          </div>
                        ) : (
                          <div className="flex items-end justify-center">
                            {toPriceFormat(price)}
                            <span className="font-size-secondary">
                              ({umin}u)
                            </span>
                          </div>
                        )}

                        <ButtonAddCart
                          catId={cat}
                          cartData={{
                            id: size,
                            qtt: umin,
                            discounts: {
                              follow: discount_,
                            },
                          }}
                          inCart={inCart && cartCat[size]?.qtt === umin}
                          handleAdd={handleAdd}
                        />
                      </div>
                    </td>
                  );
                })}
              </motion.tr>
            );
          })}

          <tr>
            <td className="pt-4">
              {data?.rows?.length < data?.total && (
                <Button
                  ref={ref}
                  size="lg"
                  className="bg-custom1-2 text-custom2--2 font-bold text-xl hover:scale-105"
                  onPress={() => showMore(cat)}
                >
                  +Mas
                </Button>
              )}
            </td>
            <td colSpan={4}></td>
          </tr>
        </tbody>
      </table>
    </div>
  );
}

export default TablePrices;
